- Terraform Cloud and Sentinel governance
- Env-to-workspace mapping and state linkage
- CI integration with GitHub Actions for plan/apply gating
- Policy design distinguishing prod vs non-prod changes
- Local and CI testing of policies; post-merge audit of policy outcomes

## Code Example

```sentinel
import "tfplan/v2"

check = func(plan) {
  hasProdChange = false
  for _, rc in tfplan.resource_changes {
    if strings.contains(rc.address, "envs/prod/") {
      hasProdChange = true
      break
    }
  }
  // If prod resources are touched, deny unless approved in PR metadata
  if hasProdChange {
    return false
  }
  return true
}
```

