## Code Example
```javascript
// Minimal Sentinel-like policy (illustrative)
import "tfplan/v2"
import "strings"

let prodChange = false
for (rc in tfplan.resource_changes) {
  if (strings.contains(rc.address, ".prod.")) {
    if (rc.change.actions.includes("create") || rc.change.actions.includes("update") || rc.change.actions.includes("delete")) {
      prodChange = true
    }
