## Code Example
```javascript
// Node.js validator skeleton
const plan = require('./plan.json');
let ok = true;
(plan.resource_changes || []).forEach(r => {
  const tags = (r.change?.after?.tags) || {};
  if (!tags.CostCenter || !tags.Env) ok = false;
});
process.exit(ok ? 0 : 1);
```

