## Code Example
```javascript
// Node.js snippet to validate plan.json plan boundaries
const fs=require('fs');
const plan=JSON.parse(fs.readFileSync('plan.json','utf8'));
const resources=plan?.planned_values?.root_module?.resources||[];
const ok=resources.every(r=>r.address.startsWith('modules/qa/')||r.address.includes('environment=qa'));
process.exit(ok?0:1);
```

